scriptTask.script:

var caseId = execution.getVariable("caseId");
var investigatorId = execution.getVariable("investigatorId");
java.lang.System.out.println("Investigation task retrieved for case: " + caseId + " by investigator: " + investigatorId);
execution.setVariable("taskRetrievalLogged", true);


var caseId = execution.getVariable("caseId");
java.lang.System.out.println("Updating case " + caseId + " status to PENDING_FINAL_APPROVAL");
execution.setVariable("caseStatus", "STATUS_22_PENDING_FINAL_APPROVAL");
execution.setVariable("previousStatus", "STATUS_20_IN_PROGRESS");
execution.setVariable("statusUpdated", true);


var caseId = execution.getVariable("caseId");
java.lang.System.out.println("Marking investigation task as complete for case: " + caseId);
execution.setVariable("investigationTaskStatus", "STATUS_30_COMPLETED");
execution.setVariable("investigationTaskCompleted", true);


var caseId = execution.getVariable("caseId");
var approvalTaskId = execution.getVariable("approvalTaskId");
var recommendedOutcome = execution.getVariable("recommendedOutcome");

java.lang.System.out.println("Creating approval task " + approvalTaskId + " for case: " + caseId);
java.lang.System.out.println("Recommended outcome: " + recommendedOutcome);

execution.setVariable("approvalTaskCreated", true);
execution.setVariable("approvalTaskStatus", "STATUS_01_UNASSIGNED");
execution.setVariable("approvalTaskName", "Approve case closure");


var caseId = execution.getVariable("caseId");
var approvalTaskId = execution.getVariable("approvalTaskId");
var candidateGroup = execution.getVariable("candidateGroup");

java.lang.System.out.println("Sending notification to " + candidateGroup + " group");
java.lang.System.out.println("New approval task: " + approvalTaskId + " for case: " + caseId);

// In real implementation, this would trigger actual notifications
// e.g., email, webhook, in-app notification
execution.setVariable("supervisorNotified", true);
execution.setVariable("notificationSentAt", new java.util.Date().toString());


var approvalTaskId = execution.getVariable("approvalTaskId");
var caseId = execution.getVariable("caseId");

java.lang.System.out.println("Logging creation of approval task: " + approvalTaskId);
java.lang.System.out.println("For case: " + caseId);
execution.setVariable("taskCreationLogged", true);


var approvalTaskId = execution.getVariable("approvalTaskId");
var candidateGroup = execution.getVariable("candidateGroup");

java.lang.System.out.println("Logging assignment of task: " + approvalTaskId);
java.lang.System.out.println("Assigned to candidate group: " + candidateGroup);
execution.setVariable("taskAssignmentLogged", true);


var caseId = execution.getVariable("caseId");
var finalOutcome = execution.getVariable("finalOutcome");
var supervisorComments = execution.getVariable("supervisorComments");

java.lang.System.out.println("Case " + caseId + " approved for closure");
java.lang.System.out.println("Final outcome: " + finalOutcome);
if (supervisorComments != null) {
    java.lang.System.out.println("Supervisor comments: " + supervisorComments);
}

execution.setVariable("caseApproved", true);
execution.setVariable("finalStatus", finalOutcome);
execution.setVariable("closedAt", new java.util.Date().toString());


var caseId = execution.getVariable("caseId");
var supervisorComments = execution.getVariable("supervisorComments");

java.lang.System.out.println("Case " + caseId + " closure rejected");
java.lang.System.out.println("Returning to investigator with comments: " + supervisorComments);

execution.setVariable("caseRejected", true);
execution.setVariable("caseStatus", "STATUS_03_RETURNED");
execution.setVariable("returnedToInvestigator", true);


var caseId = execution.getVariable("caseId");
var supervisorComments = execution.getVariable("supervisorComments");

java.lang.System.out.println("Case " + caseId + " returned for additional review");
java.lang.System.out.println("Supervisor feedback: " + supervisorComments);

execution.setVariable("returnedForReview", true);
execution.setVariable("caseStatus", "STATUS_20_IN_PROGRESS");
execution.setVariable("additionalReviewRequired", true);
